 1	import * as React from 'react';
 2	import { Modal, ModalVariant } from '@patternfly/react-core';
 3	import { useTranslation } from 'react-i18next';
 4	import { DetailsRendererFunction } from './QuickSearchDetails';
 5	import QuickSearchModalBody from './QuickSearchModalBody';
 6	import { QuickSearchData } from './utils/quick-search-types';
 7	import './QuickSearchModal.scss';
 8	import { useBoundingClientRect } from './useBoundingClientRect';
 9	import { TaskSearchCallback } from '../pipeline-builder/types';
10	
11	interface QuickSearchModalProps {
12	  isOpen: boolean;
13	  namespace: string;
14	  closeModal: () => void;
15	  allCatalogItemsLoaded: boolean;
16	  searchCatalog: (searchTerm: string) => QuickSearchData;
17	  searchPlaceholder: string;
18	  viewContainer?: HTMLElement;
19	  limitItemCount?: number;
20	  icon?: React.ReactNode;
21	  detailsRenderer?: DetailsRendererFunction;
22	  callback?: TaskSearchCallback;
23	  setFailedTasks?: React.Dispatch<React.SetStateAction<string[]>>;
24	}
25	
26	const QuickSearchModal: React.FC<QuickSearchModalProps> = ({
27	  isOpen,
28	  namespace,
29	  closeModal,
30	  searchCatalog,
31	  searchPlaceholder,
32	  allCatalogItemsLoaded,
33	  viewContainer,
34	  icon,
35	  limitItemCount,
36	  detailsRenderer,
37	  callback,
38	  setFailedTasks,
39	}) => {
40	  const { t } = useTranslation('plugin__pipelines-console-plugin');
41	  const clientRect = useBoundingClientRect(viewContainer);
42	  const maxHeight = clientRect?.height;
43	  const maxWidth = clientRect?.width;
44	
45	  return viewContainer ? (
46	    <Modal
47	      className="ocs-quick-search-modal"
48	      variant={ModalVariant.medium}
49	      aria-label={t('Quick search')}
50	      isOpen={isOpen}
51	      showClose={false}
52	      position="top"
53	      positionOffset="15%"
54	      hasNoBodyWrapper
55	      appendTo={viewContainer}
56	    >
57	      <QuickSearchModalBody
58	        allCatalogItemsLoaded={allCatalogItemsLoaded}
59	        searchCatalog={searchCatalog}
60	        searchPlaceholder={searchPlaceholder}
61	        namespace={namespace}
62	        closeModal={closeModal}
63	        limitItemCount={limitItemCount}
64	        icon={icon}
65	        detailsRenderer={detailsRenderer}
66	        maxDimension={{ maxHeight, maxWidth }}
67	        viewContainer={viewContainer}
68	        callback={callback}
69	        setFailedTasks={setFailedTasks}
70	      />
71	    </Modal>
72	  ) : null;
73	};
74	
75	export default QuickSearchModal;

